import{_ as a,c as s,a as i,o as n}from"./app-6Yjp8K1A.js";const t={};function m(r,e){return n(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="mixins的引入" tabindex="-1"><a class="header-anchor" href="#mixins的引入"><span>mixins的引入</span></a></h1><h2 id="什么是mixins" tabindex="-1"><a class="header-anchor" href="#什么是mixins"><span>什么是mixins</span></a></h2><p>混入 (mixin) 提供了一种非常灵活的方式，来分发 Vue 组件中的可复用功能。一个混入对象可以包含任意组件选项。当组件使用混入对象时，所有混入对象的选项将被“混合”进入该组件本身的选项。 混入( mixins)是vue官方文档提出的 关于vue复用性的一种方式 。</p><p>应用场景： 当组件需要重复定义属性与方法时，引入mixins特性</p><h2 id="如何使用" tabindex="-1"><a class="header-anchor" href="#如何使用"><span>如何使用</span></a></h2><p>mixins是一个js对象，它可以包含我们组件中script项中的任意功能选项，如data、components、methods 、created、computed等等</p><p><img src="https://img-blog.csdnimg.cn/img_convert/a86dba646b9916dda1dcc0c4bdf4a97b.png" alt="img"></p><h2 id="混入特性" tabindex="-1"><a class="header-anchor" href="#混入特性"><span>混入特性</span></a></h2><p>方法和参数在各组件中不共享，虽然组件调用了mixins并将其属性合并到自身组件中来了，但是其属性只会被当前组件所识别并不会被共享，也就是其他组件无法从当前组件中获取到mixins中的数据和方法。</p>',9)])])}const o=a(t,[["render",m]]),p=JSON.parse('{"path":"/%E5%89%8D%E7%AB%AF%E6%8A%80%E6%9C%AF/Vue/mixins.html","title":"mixins的引入","lang":"zh-CN","frontmatter":{},"git":{"updatedTime":1773394873000,"contributors":[{"name":"wulr","username":"wulr","email":"wulr@eastcom-sw.com","commits":1,"url":"https://github.com/wulr"}],"changelog":[{"hash":"2e05be3a6e915f9542c6b5a3b229ee576fde38ba","time":1773394873000,"email":"wulr@eastcom-sw.com","author":"wulr","message":"Remove spaces from MD filenames and update references"}]},"filePathRelative":"前端技术/Vue/mixins.md"}');export{o as comp,p as data};
